#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim) {
    int i, j, k, offset;
    float *shadow;
    float *dia, *peri_row, *peri_col;

    // Allocate working arrays (equivalent to OpenCL local memory)
    shadow = (float*)malloc(sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);
    dia = (float*)malloc(sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);
    peri_row = (float*)malloc(sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);
    peri_col = (float*)malloc(sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        // lud_diagonal: Load diagonal block into shadow
        #pragma omp parallel for collapse(2)
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = offset * matrix_dim + offset;
                shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx + i * matrix_dim];
            }
        }

        // Process diagonal block
        for (i = 0; i < BLOCK_SIZE - 1; i++) {
            #pragma omp parallel for
            for (int tx = i + 1; tx < BLOCK_SIZE; tx++) {
                for (j = 0; j < i; j++) {
                    shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                }
                shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
            }

            #pragma omp parallel for
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                for (j = 0; j < i + 1; j++) {
                    shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
                }
            }
        }

        // Write back diagonal
        #pragma omp parallel for collapse(2)
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = (offset + 1) * matrix_dim + offset;
                m[array_offset + tx + i * matrix_dim] = shadow[i * BLOCK_SIZE + tx];
            }
        }

        // lud_perimeter: Load and process perimeter for all perimeter blocks
        int num_perimeter_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

        for (int bx = 0; bx < num_perimeter_blocks; bx++) {
            #pragma omp parallel for
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int idx = tx;
                int array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE / 2; i++) {
                    dia[i * BLOCK_SIZE + idx] = m[array_offset + idx + i * matrix_dim];
                    array_offset += matrix_dim;
                }

                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx + i * matrix_dim];
                    array_offset += matrix_dim;
                }
            }

            #pragma omp parallel for
            for (int tx = BLOCK_SIZE; tx < 2 * BLOCK_SIZE; tx++) {
                int idx = tx - BLOCK_SIZE;
                int array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
                for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                    dia[i * BLOCK_SIZE + idx] = m[array_offset + idx + i * matrix_dim];
                    array_offset += matrix_dim;
                }

                array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx + i * matrix_dim];
                    array_offset += matrix_dim;
                }
            }

            // Process perimeter
            #pragma omp parallel for
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int idx = tx;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < i; j++) {
                        peri_row[i * BLOCK_SIZE + idx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
                    }
                }
            }

            #pragma omp parallel for
            for (int tx = BLOCK_SIZE; tx < 2 * BLOCK_SIZE; tx++) {
                int idx = tx - BLOCK_SIZE;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < i; j++) {
                        peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                    }
                    peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
                }
            }

            // Write back perimeter
            #pragma omp parallel for
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int idx = tx;
                int array_offset = (offset + 1) * matrix_dim + offset;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    m[array_offset + (bx + 1) * BLOCK_SIZE + idx + i * matrix_dim] = peri_row[i * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            }

            #pragma omp parallel for
            for (int tx = BLOCK_SIZE; tx < 2 * BLOCK_SIZE; tx++) {
                int idx = tx - BLOCK_SIZE;
                int array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    m[array_offset + idx + i * matrix_dim] = peri_col[i * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            }
        }

        // lud_internal: Process internal blocks
        #pragma omp parallel for collapse(3)
        for (int by = 0; by < (matrix_dim - offset) / BLOCK_SIZE - 1; by++) {
            for (int bx = 0; bx < (matrix_dim - offset) / BLOCK_SIZE - 1; bx++) {
                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        int global_row_id = offset + (by + 1) * BLOCK_SIZE;
                        int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

                        peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                        peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];

                        float sum = 0;
                        for (int i = 0; i < BLOCK_SIZE; i++) {
                            sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
                        }
                        m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                    }
                }
            }
        }
    }

    // Final diagonal block
    offset = matrix_dim - BLOCK_SIZE;
    #pragma omp parallel for collapse(2)
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int array_offset = offset * matrix_dim + offset;
            shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx + i * matrix_dim];
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for
        for (int tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++) {
                shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            }
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }
    }

    free(shadow);
    free(dia);
    free(peri_row);
    free(peri_col);
}
